transform_js:
var maxV = 0;
rawData.rows.forEach(function(r) { if (r.v > maxV) maxV = r.v; });
var total = rawData.rows.length;
transformedData = rawData.rows.map(function(r, i) {
  var angle = (i / total) * Math.PI * 4;
  var radius = 20 + (i / total) * 80;
  var x = radius * Math.cos(angle);
  var y = radius * Math.sin(angle);
  return { value: [x, y, r.v], name: 'T' + r.t, symbolSize: 6 + (r.v / maxV) * 14 };
});

echarts_js:
option = {
  title: { text: 'Seasonal Spiral', left: 'center' },
  tooltip: { formatter: function(p) { return p.data.name + ': ' + p.data.value[2]; } },
  xAxis: { type: 'value', show: false },
  yAxis: { type: 'value', show: false },
  visualMap: { min: 0, max: 100, calculable: true, inRange: { color: ['#d4e4fc', '#1a3cab'] }, right: '5%', top: 'center' },
  series: [{
    type: 'scatter',
    data: transformedData,
    itemStyle: { opacity: 0.85 }
  }]
};
